import React from 'react';

function ClientList({ clients }) {
  return (
    <div>
      <h2>Liste des Clients</h2>
      <ul>
        {clients.map(client => (
          <li key={client.codeCli}>
            {client.nomCli} {client.prenomCli} - {client.telCli}
          </li>
        ))}
      </ul>
    </div>
  );
}

export default ClientList;
